format_data:
{"report_type": "HTML", "html": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<style>
  @page { margin: 12mm 14mm 8mm 14mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 9pt; color: #1a1a2e; background: #fff; }
  .page { max-width: 820px; margin: 0 auto; padding: 0; }

  .hotel-logo { max-height: 70px; max-width: 140px; }
  .logo-box {
    display: inline-block; width: 46px; height: 46px;
    background: #1a1a2e; color: #fff; font-size: 16pt; font-weight: 700;
    text-align: center; line-height: 46px; border-radius: 5px;
  }
  .hotel-name { font-size: 14pt; font-weight: 700; color: #1a1a2e; }
  .hotel-sub { font-size: 7.5pt; color: #6b7280; margin-top: 2px; line-height: 1.5; }
  .doc-title { font-size: 13pt; font-weight: 700; color: #1a1a2e; }
  .doc-subtitle { font-size: 7pt; color: #6b7280; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 2px; }
  .doc-ref { font-size: 8pt; color: #6b7280; margin-top: 6px; line-height: 1.7; }
  .doc-ref strong { color: #374151; }
  .header-divider { border: none; border-top: 2px solid #1a1a2e; margin: 14px 0 16px; }

  .pill {
    display: inline-block; padding: 2px 9px; border-radius: 10px;
    font-size: 7pt; font-weight: 700; text-transform: uppercase;
    letter-spacing: 0.4px; margin-right: 5px;
    border: 1px solid #d1d5db; background: #f9fafb; color: #374151;
  }
  .pills-row { margin-bottom: 14px; }

  .section-title { font-size: 7.5pt; font-weight: 700; color: #1a1a2e; text-transform: uppercase; letter-spacing: 0.6px; background: #f1f3f8; border-left: 3px solid #1a1a2e; border-bottom: 1px solid #d1d5db; padding: 5px 9px; margin-top: 14px; margin-bottom: 8px; }

  .info-table { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
  .info-table td {
    padding: 4px 8px; font-size: 9pt;
    border-bottom: 1px solid #f1f5f9;
    vertical-align: middle; white-space: nowrap;
  }
  .info-table tr:last-child td { border-bottom: none; }
  .info-key { width: 22%; color: #1a1a2e; font-weight: 700; }
  .info-val { width: 28%; color: #1a1a2e; font-weight: 400; }

  .notes-box {
    border: 1px solid #e5e7eb; border-radius: 4px;
    padding: 8px 12px; font-size: 8.5pt; color: #374151; margin-bottom: 4px;
    line-height: 1.6;
  }

  .data-table { width: 100%; border-collapse: collapse; font-size: 8.5pt; margin-bottom: 4px; }
  .data-table thead tr { background: #f1f3f8; color: #1a1a2e; border-bottom: 2px solid #1a1a2e; }
  .data-table thead th { padding: 6px 9px; text-align: left; font-size: 7pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.4px; }
  .data-table tbody tr:nth-child(even) { background: #f9fafb; }
  .data-table tbody td { padding: 7px 9px; border-bottom: 1px solid #f1f5f9; color: #374151; }

  .value-box {
    background: #f9fafb; border: 1px solid #e5e7eb; border-radius: 8px;
    padding: 14px 20px; margin-bottom: 4px;
  }
  .value-box table { width: 100%; border-collapse: collapse; }
  .value-box td { padding: 5px 0; font-size: 9pt; border-bottom: 1px solid #f1f5f9; }
  .value-box tr:last-child td { border-bottom: none; }
  .value-box .v-label { color: #6b7280; width: 50%; }
  .value-box .v-value { text-align: right; font-weight: 600; color: #1a1a2e; }
  .value-box .total-row td { font-weight: 700; font-size: 10pt; color: #1a1a2e; background: none; }

  .footer-divider { border: none; border-top: 1px solid #e5e7eb; margin: 20px 0 12px; }
  .footer-note { font-size: 7pt; color: #9ca3af; line-height: 1.7; }
  .footer-company { font-size: 9pt; font-weight: 700; color: #1a1a2e; }
  .footer-date { font-size: 7pt; color: #9ca3af; margin-top: 2px; }
  .sig-line { margin-top: 16px; border-top: 1px solid #e5e7eb; padding-top: 5px; font-size: 7pt; color: #9ca3af; text-align: center; }
</style>
</head>
<body>
<div class="page">

  <!-- HEADER -->
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="55%" valign="top">
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="padding-right:10px;" valign="middle">
              {% if hotel_logo %}
                <img src="{{ hotel_logo }}" alt="{{ company }}" class="hotel-logo" />
              {% else %}
                <div class="logo-box">{{ (company or 'H')[:1] }}</div>
              {% endif %}
            </td>
            <td valign="middle">
              <div class="hotel-name">{{ company }}</div>
              <div class="hotel-sub">
                {% if hotel_tagline %}{{ hotel_tagline }}<br>{% endif %}
                {% if hotel_address %}{{ hotel_address }}<br>{% endif %}
                {% if hotel_phone %}{{ hotel_phone }}{% if hotel_email %} &middot; {% endif %}{% endif %}
                {% if hotel_email %}{{ hotel_email }}{% endif %}
              </div>
            </td>
          </tr>
        </table>
      </td>
      <td valign="top" align="right">
        <div class="doc-title">Complimentary Record</div>
        <div class="doc-subtitle">Complimentary Voucher</div>
        <div class="doc-ref">
          <strong>Ref:</strong> {{ record.name }}<br>
          <strong>Generated:</strong> {{ generated_at }}
        </div>
      </td>
    </tr>
  </table>
  <hr class="header-divider" />

  <!-- STATUS PILLS -->
  <div class="pills-row">
    {% set st = (record.status or '') | lower %}
    {% if st == 'approved' %}<span class="pill">&#10003; Approved</span>
    {% elif st == 'consumed' %}<span class="pill">&#10003; Consumed</span>
    {% elif st == 'pending' %}<span class="pill">&#9679; Pending</span>
    {% elif st == 'in progress' %}<span class="pill">&#9679; In Progress</span>
    {% elif st == 'expired' %}<span class="pill">&#10007; Expired</span>
    {% else %}<span class="pill">{{ record.status }}</span>{% endif %}
    {% if record.complimentary_type %}<span class="pill">{{ record.complimentary_type }}</span>{% endif %}
    {% if record.department %}<span class="pill">{{ record.department }}</span>{% endif %}
  </div>

  <!-- COMPLIMENTARY DETAILS -->
  <div class="section-title">Complimentary Details</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup>
      <col style="width:22%" /><col style="width:28%" />
      <col style="width:22%" /><col style="width:28%" />
    </colgroup>
    <tr>
      <td class="info-key">Reference</td>
      <td class="info-val">{{ record.name }}</td>
      <td class="info-key">Type</td>
      <td class="info-val">{{ record.complimentary_type or '&mdash;' }}</td>
    </tr>
    <tr>
      <td class="info-key">Guest</td>
      <td class="info-val">{{ record.guest or '&mdash;' }}</td>
      <td class="info-key">Room</td>
      <td class="info-val">{{ record.room or '&mdash;' }}</td>
    </tr>
    <tr>
      <td class="info-key">Department</td>
      <td class="info-val">{{ record.department or '&mdash;' }}</td>
      <td class="info-key">Issue Date</td>
      <td class="info-val">{{ record.issue_date or '&mdash;' }}</td>
    </tr>
    <tr>
      <td class="info-key">Expiry Date</td>
      <td class="info-val">{{ record.expiry_date or '&mdash;' }}</td>
      <td class="info-key">Status</td>
      <td class="info-val">{{ record.status or '&mdash;' }}</td>
    </tr>
    {% if record.reservation %}
    <tr>
      <td class="info-key">Reservation</td>
      <td class="info-val" colspan="3">{{ record.reservation }}</td>
    </tr>
    {% endif %}
    {% if record.redemption_rule %}
    <tr>
      <td class="info-key">Redemption Rule</td>
      <td class="info-val" colspan="3">{{ record.redemption_rule }}</td>
    </tr>
    {% endif %}
  </table>

  <!-- VALUE SUMMARY -->
  <div class="section-title">Value Summary</div>
  <div class="value-box">
    <table cellpadding="0" cellspacing="0">
      <tr>
        <td class="v-label">Total Value</td>
        <td class="v-value">&#x20a6;{{ "{:,.2f}".format((record.value or 0) | float) }}</td>
      </tr>
      {% if record.redeemed_amount %}
      <tr>
        <td class="v-label">Redeemed Amount</td>
        <td class="v-value">&#x20a6;{{ "{:,.2f}".format((record.redeemed_amount or 0) | float) }}</td>
      </tr>
      {% endif %}
      <tr class="total-row">
        <td class="v-label">Remaining Value</td>
        <td class="v-value">&#x20a6;{{ "{:,.2f}".format((record.remaining_value or record.value or 0) | float) }}</td>
      </tr>
    </table>
  </div>

  <!-- REASON -->
  {% if record.reason %}
  <div class="section-title">Reason</div>
  <div class="notes-box">{{ record.reason }}</div>
  {% endif %}

  <!-- NOTES -->
  {% if record.note %}
  <div class="section-title">Notes</div>
  <div class="notes-box">{{ record.note }}</div>
  {% endif %}

  <!-- APPROVAL & CONSUMPTION -->
  <div class="section-title">Approval &amp; Consumption</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup>
      <col style="width:22%" /><col style="width:28%" />
      <col style="width:22%" /><col style="width:28%" />
    </colgroup>
    <tr>
      <td class="info-key">Issued By</td>
      <td class="info-val">{{ record.issued_by or '&mdash;' }}</td>
      <td class="info-key">Approved By</td>
      <td class="info-val">{{ record.approved_by or '&mdash;' }}</td>
    </tr>
    <tr>
      <td class="info-key">Approved On</td>
      <td class="info-val">{{ record.approved_on or '&mdash;' }}</td>
      <td class="info-key">Consumed On</td>
      <td class="info-val">{{ record.consumed_on or '&mdash;' }}</td>
    </tr>
    {% if record.consumption_reference %}
    <tr>
      <td class="info-key">Consumption Ref</td>
      <td class="info-val" colspan="3">{{ record.consumption_reference }}</td>
    </tr>
    {% endif %}
  </table>

  <!-- FOOTER -->
  <hr class="footer-divider" />
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="60%" valign="bottom">
        <div class="footer-note">
          This record is generated by the {{ company }} Property Management System.<br>
          <strong style="color:#374151;">Ref: {{ record.name }} &nbsp;&middot;&nbsp; Generated: {{ generated_at }}</strong>
        </div>
      </td>
      <td valign="bottom" align="right">
        <div class="footer-company">{{ company }}</div>
        <div class="footer-date">{{ generated_at }}</div>
        <div class="sig-line">Authorised Signature</div>
      </td>
    </tr>
  </table>

</div>
</body>
</html>"}
